import{_ as i,c as a,o as e,ag as t}from"./chunks/framework.D4Vqf8I7.js";const r=JSON.parse('{"title":"Kubernetes","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"docs/wi/kubernetes.md","filePath":"docs/wi/kubernetes.md","lastUpdated":1784711311000}'),p={name:"docs/wi/kubernetes.md"};function l(h,s,n,k,d,o){return e(),a("div",null,s[0]||(s[0]=[t(`<h1 id="kubernetes" tabindex="-1">Kubernetes <a class="header-anchor" href="#kubernetes" aria-label="Permalink to &quot;Kubernetes&quot;">​</a></h1><p><img src="https://platform9.com/media/kubernetes-constructs-concepts-architecture.jpg" alt=""></p><h2 id="развертывание-вашего-первого-приложения" tabindex="-1">Развёртывание вашего первого приложения <a class="header-anchor" href="#развертывание-вашего-первого-приложения" aria-label="Permalink to &quot;Развёртывание вашего первого приложения&quot;">​</a></h2><p><img src="https://kubernetes.io/docs/tutorials/kubernetes-basics/public/images/module_02_first_app.svg" alt=""></p><p>Вы можете создавать и управлять деплойментами через консольный инструмент Kubernetes под названием <code>kubectl</code>. Kubectl использует Kubernetes API для работы с кластером. В этом модуле вы узнаете про наиболее используемые команды kubectl, необходимые для создания деплойментов, которые будут запускать приложения в кластере Kubernetes.</p><h3 id="основы-kubectl" tabindex="-1">Основы kubectl <a class="header-anchor" href="#основы-kubectl" aria-label="Permalink to &quot;Основы kubectl&quot;">​</a></h3><p>Общий формат команд kubectl выглядит так: <code>kubectl действие ресурс</code></p><p>Эта команда выполнит указанное <em>действие</em> (например, create, describe или delete) с указанным <em>ресурсом</em> (например, node или deployment). Можно воспользоваться справкой через флаг <code>--help</code> после подкоманды, чтобы получить дополнительные сведения о возможных параметрах (например: <code>kubectl get nodes --help</code>).</p><p>Убедитесь, что kubectl настроена на подключение к вашему кластеру, выполнив команду:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span></span></code></pre></div><p>Убедитесь, что kubectl установлена и вы можете увидеть версию и у клиента, и у сервера.</p><p>Чтобы увидеть список узлов кластера, выполните команду:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span></span></code></pre></div><p>Вы увидите доступные узлы. Позже Kubernetes выберет, куда задеплоить ваше приложение, руководствуясь данными о доступных узлах.</p><h3 id="деплои-приложения" tabindex="-1">Деплой приложения <a class="header-anchor" href="#деплои-приложения" aria-label="Permalink to &quot;Деплой приложения&quot;">​</a></h3><p>Давайте развернём первое приложение в Kubernetes с помощью команды <code>kubectl create deployment</code>. Для этого потребуется указать имя деплоймента и путь к образу приложения (используйте полный URL репозитория для образов, которые располагаются вне Docker Hub).</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kubernetes-bootcamp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image=gcr.io/google-samples/kubernetes-bootcamp:v1</span></span></code></pre></div><p>Отлично! Создав этот Deployment, вы только что развернули первое приложение. Команда привела к выполнению следующих действий:</p><ul><li>поиск подходящего узла, на котором можно запустить экземпляр приложения (у нас доступен только 1 узел);</li><li>планирование (размещение) приложения для запуска на этом узле;</li><li>настройка кластера на повторное размещение экземпляра на новом узле, когда это потребуется.</li></ul><p>Чтобы увидеть список деплойментов, выполните команду <code>kubectl get deployments</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments</span></span></code></pre></div><p>Вы увидите, что есть 1 деплоймент, в котором запущен единственный экземпляр приложения. Этот экземпляр работает в контейнере на узле кластера.</p><h3 id="просмотр-приложения" tabindex="-1">Просмотр приложения <a class="header-anchor" href="#просмотр-приложения" aria-label="Permalink to &quot;Просмотр приложения&quot;">​</a></h3><p>Поды, которые запущены внутри Kubernetes, работают в частной, изолированной сети. По умолчанию они видны для других подов и сервисов того же Kubernetes-кластера, однако не за пределами этой сети. Когда мы используем утилиту <code>kubectl</code>, мы взаимодействуем с нашим приложением через API-эндпоинт.</p><p>О других возможностях сделать приложение доступным вне кластера Kubernetes мы расскажем позже, в разделе <a href="https://kubernetes.io/ru/docs/tutorials/kubernetes-basics/expose/" target="_blank" rel="noreferrer">Открытие доступа к приложению</a>.</p><p>Команда <code>kubectl proxy</code> создаст прокси, который перенаправляет взаимодействие в частную сеть, доступную в рамках кластера. Во время своей работы прокси не выводит никаких сообщений, а остановить его можно нажатием на control-C.</p><p><strong>Для запуска прокси потребуется открыть второе окно с терминалом.</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> proxy</span></span></code></pre></div><p>Теперь у нас есть соединение между хостом (терминалом) и Kubernetes-кластером. Прокси обеспечивает прямой доступ к API из терминала.</p><p>Через эндпоинт от прокси можно увидеть все API. Например, с помощью <code>curl</code> мы можем напрямую через API узнать версию:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8001/version</span></span></code></pre></div><div class="info custom-block github-alert"><p class="custom-block-title">Info</p><p><strong>Примечание:</strong> если порт 8001 недоступен, убедитесь, что выполенная вами ранее команда <code>kubectl proxy</code> была запущена во втором терминале.</p></div><p>Сервер API автоматически создаст эндпоинт для каждого пода в соответствии с именем пода, который будет также доступен через прокси.</p><p>Для начала узнаем имя пода и сохраним его в переменной окружения POD_NAME:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> POD_NAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> go-template</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --template</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{{range .items}}{{.metadata.name}}{{&quot;\\n&quot;}}{{end}}&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Pod:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $POD_NAME</span></span></code></pre></div><p>Теперь получим доступ к поду через проксированный API, выполнив команду:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8001/api/v1/namespaces/default/pods/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$POD_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:8080/proxy/</span></span></code></pre></div><h3 id="проверка-конфигурации-приложения" tabindex="-1">Проверка конфигурации приложения <a class="header-anchor" href="#проверка-конфигурации-приложения" aria-label="Permalink to &quot;Проверка конфигурации приложения&quot;">​</a></h3><p>Давайте проверим, что приложение, которое мы развернули ранее, работает. Воспользуемся командой <code>kubectl get</code> и посмотрим на существующие поды:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>Если работающих подов нет, подождите несколько секунд и выведите их список снова. Как только увидите работающий под, следуйте инструкциям ниже.</p><p>Теперь, чтобы увидеть, какие контейнеры находятся внутри этого пода и какие образы использовались при сборке этих контейнеров, выполним команду <code>kubectl describe pods</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>Здесь можно увидеть подробности о контейнере пода: IP-адрес, используемые порты и список событий, относящихся к жизненному циклу пода.</p><p>У подкоманды describe подробный вывод. В частности, он затрагивает концепции, которые мы ещё не рассматривали, но не волнуйтесь — они станут понятнее в дальнейшем.</p><p><em><strong>Примечание:</strong> подкоманду describe можно использовать для получения информации о многих примитивах Kubernetes, включая узлы (Nodes), поды (Pods) и деплойменты (Deployments). Вывод describe предназначен для чтения человеком, не для использования в скриптах.</em></p><h3 id="просмотр-логов-контеинера" tabindex="-1">Просмотр логов контейнера <a class="header-anchor" href="#просмотр-логов-контеинера" aria-label="Permalink to &quot;Просмотр логов контейнера&quot;">​</a></h3><p>Всё, что обычное приложение отправляет в стандартный вывод (standard output), становится логами контейнера в поде. Получить эти логи можно с помощью команды <code>kubectl logs</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$POD_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p><em><strong>Примечание:</strong> указывать название контейнера не требуется, потому что в данном поде у нас единственный контейнер.</em></p><h3 id="выполнение-команд-в-контеинере" tabindex="-1">Выполнение команд в контейнере <a class="header-anchor" href="#выполнение-команд-в-контеинере" aria-label="Permalink to &quot;Выполнение команд в контейнере&quot;">​</a></h3><p>Когда под запущен и работает, в его контейнерах можно выполнять команды. Для этого воспользуемся подкомандой <code>exec</code> и передадим имя пода в качестве параметра. Выведем список переменных окружения в контейнере:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$POD_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span></span></code></pre></div><p>Вновь отметим, что название контейнера можно не указывать, поскольку в этом поде у нас единственный контейнер.</p><p>Далее запустим Bash-сессию в контейнере пода:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ti</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $POD_NAME </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre></div><p>Откроется консоль в контейнере, в котором работает NodeJS-приложение. Исходный код приложения находится в файле server.js:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server.js</span></span></code></pre></div><p>Также можно убедиться, что приложение запущено и работает, обратившись к нему через curl:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8080</span></span></code></pre></div><p><em><strong>Примечание:</strong> мы здесь использовали localhost, поскольку выполняли команду внутри пода NodeJS. Если у вас не получается подключиться к localhost:8080, проверьте, что запускали команду <code>kubectl exec</code>, а сейчас вызываете команду из пода.</em></p><p>Чтобы закрыть подключение к контейнеру, введите exit.</p><h3 id="создание-сервиса-для-открытия-доступа-к-приложению" tabindex="-1">Создание сервиса для открытия доступа к приложению <a class="header-anchor" href="#создание-сервиса-для-открытия-доступа-к-приложению" aria-label="Permalink to &quot;Создание сервиса для открытия доступа к приложению&quot;">​</a></h3><p><img src="https://kubernetes.io/docs/tutorials/kubernetes-basics/public/images/module_04_services.svg" alt=""></p><p>Сервис направляет трафик через набор подов. Сервисы — это абстракция, позволяющая взаимозаменять поды Kubernetes без ущерба для работы приложения. Сервисы в Kubernetes находят и маршрутизируют трафик между зависимыми подами (это могут быть фронтенд- и бэкенд-компоненты приложения).</p><p>Сервисы для выбора набора подов используют <a href="https://kubernetes.io/docs/concepts/overview/working-with-objects/labels" target="_blank" rel="noreferrer">лейблы и селекторы</a>. Лейблы — пары ключ-значение, добавленные к объектам; например, они могут использоваться чтобы:</p><ul><li>идентифицировать объекты для окружений разработки, тестирования и production;</li><li>встроить теги версии;</li><li>классифицировать объекты через теги.</li></ul><p><img src="https://kubernetes.io/docs/tutorials/kubernetes-basics/public/images/module_04_labels.svg" alt=""></p><p>Лейблы могут добавляться во время создания объектов или после этого. Они также могут быть изменены в любое время. Теперь давайте откроем доступ к приложению с помощью создания сервиса и добавим лейблы.</p><h4 id="создание-нового-сервиса" tabindex="-1">Создание нового сервиса <a class="header-anchor" href="#создание-нового-сервиса" aria-label="Permalink to &quot;Создание нового сервиса&quot;">​</a></h4><p>Давайте убедимся, что приложение работает. Воспользуемся командой <code>kubectl get</code> и посмотрим на существующие поды:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>Если работающих подов нет, объекты из предыдущих разделов руководства была удалены. В таком случае вернитесь и повторно создайте деплоймент по инструкциям из раздела <a href="https://kubernetes.io/ru/docs/tutorials/kubernetes-basics/deploy-app/deploy-intro#deploy-an-app" target="_blank" rel="noreferrer">Использование kubectl для развёртывания приложения</a>. После этого подождите несколько секунд и повторно запросите список подов. Как только увидите работающий под, можно следовать инструкциям ниже.</p><p>Далее посмотрим на список уже имеющихся сервисов в кластере:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services</span></span></code></pre></div><p>У нас есть сервис под названием kubernetes. Его по умолчанию создаёт minikube при запуске кластера. Чтобы создать новый сервис и сделать его доступным для внешних пользователей, воспользуемся командой <code>expose</code> с указанием типа сервиса NodePort в качестве параметра.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> expose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployment/kubernetes-bootcamp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;NodePort&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8080</span></span></code></pre></div><p>Попробуем подкоманду <code>get services</code> ещё раз:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services</span></span></code></pre></div><p>Теперь у нас есть сервис под названием kubernetes-bootcamp. Мы можем увидеть, что у этого сервиса уникальный cluster-IP, внутренний порт и external-IP (IP соответствующего узла).</p><p>Чтобы выяснить, какой порт был открыт для внешнего мира (для сервиса со спецификацией type: NodePort), выполним подкоманду <code>describe service</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services/kubernetes-bootcamp</span></span></code></pre></div><p>Объявим переменную окружения NODE_PORT, в которую запишем значение назначенного порта узла:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NODE_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get services/kubernetes-bootcamp </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> go-template=&#39;{{(index .spec.ports 0).nodePort}}&#39;)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;NODE_PORT=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NODE_PORT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Теперь можно проверить, что приложение доступно вне кластера, с помощью <code>curl</code>, IP-адреса узла и порта, проброшенного вовне:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">minikube</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ip):</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NODE_PORT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Получим ответ от сервера. Сервис доступен внешнему миру.</p><h4 id="использование-леиблов" tabindex="-1">Использование лейблов <a class="header-anchor" href="#использование-леиблов" aria-label="Permalink to &quot;Использование лейблов&quot;">​</a></h4><p>Deployment автоматически создаёт лейбл для пода. Подкоманда <code>describe deployment</code> покажет его название (<em>key</em>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployment</span></span></code></pre></div><p>Воспользуемся этим лейблом при выводе списка подов. Для этого вызовем команду <code>kubectl get pods</code> с флагом -l и нужными значениями лейблов в качестве параметра:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app=kubernetes-bootcamp</span></span></code></pre></div><p>То же самое можно делать при выводе списка сервисов:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app=kubernetes-bootcamp</span></span></code></pre></div><p>Получим имя пода и запишем его в переменную окружения POD_NAME:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> POD_NAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get pods </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> go-template </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--template</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{{range .items}}{{.metadata.name}}{{&quot;\\n&quot;}}{{end}}&#39;)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Name of the Pod: </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$POD_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Чтобы добавить новый лейбл, воспользуемся подкомандой <code>label</code>, для которой укажем тип объекта, имя объекта и значение нового лейбла:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> label</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$POD_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version=v1</span></span></code></pre></div><p>Новый лейбл добавится к поду (мы зафиксировали версию приложения для этого пода), а мы сможем убедиться в этом с помощью команды <code>describe pod</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$POD_NAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Как видно, лейбл добавился к нашему поду. Теперь мы можем получить список всех подов, использующих новый лейбл:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version=v1</span></span></code></pre></div><p>Наш под будет в этом списке.</p><h4 id="удаление-сервиса" tabindex="-1">Удаление сервиса <a class="header-anchor" href="#удаление-сервиса" aria-label="Permalink to &quot;Удаление сервиса&quot;">​</a></h4><p>Чтобы удалить сервис, воспользуйтесь подкомандой <code>delete service</code>. В ней могут указываться и лейблы:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app=kubernetes-bootcamp</span></span></code></pre></div><p>Убедитесь, что сервис удалился:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services</span></span></code></pre></div><p>Вывод подтвердит, что сервис был удалён. Убедиться в том, что удалился соответствующий маршрут для внешнего трафика, можно через curl к доступному ранее IP и порту:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">minikube</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ip):</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NODE_PORT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Так можно убедиться, что приложение более недоступно снаружи кластера. Проверить, что приложение всё ещё работает, можно через curl, который будет выполнен внутри пода:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ti</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $POD_NAME </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8080</span></span></code></pre></div><p>Мы увидим, что приложение запущено. Оно функционирует, потому что за его работу отвечает деплоймент (Deployment). Чтобы остановить приложение, потребуется также удалить и его деплоймент.</p><h3 id="запуск-нескольких-экземпляров-приложения" tabindex="-1">Запуск нескольких экземпляров приложения <a class="header-anchor" href="#запуск-нескольких-экземпляров-приложения" aria-label="Permalink to &quot;Запуск нескольких экземпляров приложения&quot;">​</a></h3><p><img src="https://kubernetes.io/docs/tutorials/kubernetes-basics/public/images/module_05_scaling1.svg" alt=""></p><p>Для вывода списка депойментов воспользуйтесь подкомандой <code>get deployments</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments</span></span></code></pre></div><p>Вывод будет примерно следующим:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NAME                  READY   UP-TO-DATE   AVAILABLE   AGE</span></span>
<span class="line"><span>kubernetes-bootcamp   1/1     1            1           11m</span></span></code></pre></div><p>У нас должен быть 1 под. Если его нет, выполните команду ещё раз. Вывод показывает следующую информацию:</p><ul><li><em>NAME</em> — названия деплойментов (Deployments) в кластере.</li><li><em>READY</em> — соотношение CURRENT/DESIRED для его экземпляров (реплик).</li><li><em>UP-TO-DATE</em> — количество реплик, которые были обновлены до желаемого состояния.</li><li><em>AVAILABLE</em> — количество реплик, доступных для пользователей.</li><li><em>AGE</em> — сколько времени приложение было запущено.</li></ul><p>Чтобы увидеть ReplicaSet, созданные деплойментом, выполните:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rs</span></span></code></pre></div><p>Обратите внимание, что название ReplicaSet всегда форматируется как [DEPLOYMENT-NAME]-[RANDOM-STRING]. Последний фрагмент генерируется случайным образом и использует <em>pod-template-hash</em> в качестве seed-значения.</p><p>Этот вывод будет содержать два важных столбца:</p><ul><li><em>DESIRED</em> — желаемое количество экземпляров (реплик) приложения. Это значение вы определяете, когда создаёте деплоймент.</li><li><em>CURRENT</em> — количество реплик, которые работают в настоящий момент.</li></ul><p>Далее отмасштабируем деплоймент до 4 реплик. Для этого воспользуемся командой <code>kubectl scale</code>, для которой укажем тип объекта (деплоймент), его название и количество желаемых экземпляров:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments/kubernetes-bootcamp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --replicas=4</span></span></code></pre></div><p>Снова выведем список деплойментов с помощью <code>get deployments</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments</span></span></code></pre></div><p>Изменение применилось: теперь доступны 4 экземпляра приложения. Далее проверим, изменилось ли количество подов:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span></span></code></pre></div><p>Теперь у нас 4 пода с разными IP-адресами. Это изменение было зафиксировано в логе событий деплоймента. Убедиться в этом можно подкомандой <code>describe</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments/kubernetes-bootcamp</span></span></code></pre></div><p>В выводе этой команды тоже видно, что теперь у нас 4 реплики.</p><h4 id="балансировка-нагрузки" tabindex="-1">Балансировка нагрузки <a class="header-anchor" href="#балансировка-нагрузки" aria-label="Permalink to &quot;Балансировка нагрузки&quot;">​</a></h4><p>Проверим, что сервис балансирует трафик. Чтобы узнать внешний IP-адрес и порт, воспользуемся командой <code>describe service</code>, с которой уже познакомились в <a href="https://kubernetes.io/ru/docs/tutorials/kubernetes-basics/expose/expose-intro/" target="_blank" rel="noreferrer">предыдущем модуле</a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services/kubernetes-bootcamp</span></span></code></pre></div><p>Объявим переменную окружения NODE_PORT со значением порта нашего узла:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NODE_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get services/kubernetes-bootcamp </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> go-template=&#39;{{(index .spec.ports 0).nodePort}}&#39;)&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NODE_PORT=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NODE_PORT</span></span></code></pre></div><p>Далее обратимся через <code>curl</code> к проброшенному IP-адресу и порту. Выполните эту команду много раз:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">minikube</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ip):</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NODE_PORT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Каждый раз мы будем попадать на разный под. Это означает, что балансировка нагрузки работает.</p><h4 id="масштабирование-вниз" tabindex="-1">Масштабирование вниз <a class="header-anchor" href="#масштабирование-вниз" aria-label="Permalink to &quot;Масштабирование вниз&quot;">​</a></h4><p>Чтобы уменьшить деплоймент до 2 реплик, снова обратимся к подкоманде <code>scale</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments/kubernetes-bootcamp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --replicas=2</span></span></code></pre></div><p>С помощью подкоманды <code>get deployments</code> выведем список деплойментов, чтобы убедиться, что изменение применилось:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments</span></span></code></pre></div><p>Количество реплик уменьшилось до 2. Выведем список подов с <code>get pods</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wide</span></span></code></pre></div><p>Так мы убедимся, что работа 2 подов была остановлена.</p><h3 id="выполнение-плавающего-обновления" tabindex="-1">Выполнение плавающего обновления <a class="header-anchor" href="#выполнение-плавающего-обновления" aria-label="Permalink to &quot;Выполнение плавающего обновления&quot;">​</a></h3><p><img src="https://kubernetes.io/docs/tutorials/kubernetes-basics/public/images/module_06_rollingupdates1.svg" alt=""></p><p>Подобно масштабированию приложения, если деплоймент доступен извне, при обновлении сервис будет балансировать трафик только между доступными подами. Доступный под — это экземпляр, который может быть запущен для пользователей приложения.</p><p>С помощью плавающих обновлений можно:</p><ul><li>переводить приложение из одного окружения в другое (через обновления образа контейнера);</li><li>откатываться к предыдущим версиям;</li><li>осуществлять непрерывную интеграцию и непрерывную доставку приложений без простоев.</li></ul><p><em>Если деплоймент был открыт наружу, в процессе обновления сервис будет балансировать трафик только на доступные поды.</em></p><p>В инструкциях ниже мы обновим приложение до новой версии и потом откатим его обратно.</p><h4 id="обновление-версии-приложения" tabindex="-1">Обновление версии приложения <a class="header-anchor" href="#обновление-версии-приложения" aria-label="Permalink to &quot;Обновление версии приложения&quot;">​</a></h4><p>Чтобы получить список деплойментов, выполните подкоманду <code>get deployments</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments</span></span></code></pre></div><p>Для списка подов — подкоманду <code>get pods</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>Чтобы увидеть версию текущего образа в приложении, воспользуйтесь подкомандой <code>describe pods</code> и посмотрите на поле <code>Image</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>Чтобы обновить версию образа приложения до v2, воспользуемся подкомандой <code>set image</code>, для которой укажем имя деплоймента и новую версию нужного образа:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments/kubernetes-bootcamp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kubernetes-bootcamp=docker.io/jocatalin/kubernetes-bootcamp:v2</span></span></code></pre></div><p>Эта команда перевела деплоймент на использование другого образа для приложения и инициировала плавающее обновление. Статус новых и старых подов (т. е. тех, которые будут остановлены) можно проверить с помощью подкоманды <code>get pods</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><h4 id="валидация-обновления" tabindex="-1">Валидация обновления <a class="header-anchor" href="#валидация-обновления" aria-label="Permalink to &quot;Валидация обновления&quot;">​</a></h4><p>Во-первых, убедимся, что приложение работает. Доступный извне IP-адрес и порт узнаем с помощью команды <code>describe service</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services/kubernetes-bootcamp</span></span></code></pre></div><p>Объявим переменную окружения NODE_PORT со значением порта нашего узла:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NODE_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get services/kubernetes-bootcamp </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> go-template=&#39;{{(index .spec.ports 0).nodePort}}&#39;)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  </span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;NODE_PORT=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NODE_PORT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Далее обратимся через <code>curl</code> к проброшенному IP и порту:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://&quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">minikube</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ip):</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$NODE_PORT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Каждый раз при вызове этой команды <code>curl</code> вам будет попадаться другой под. Обратите внимание, что все поды теперь работают с последней версией приложения (v2).</p><p>Проверить статус обновления можно также с помощью подкоманды <code>rollout status</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rollout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments/kubernetes-bootcamp</span></span></code></pre></div><p>Увидеть текущую версию образа приложения можно подкомандой <code>describe pods</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>В поле <code>Image</code> у этого вывода убедитесь, что запущена последняя версия образа (v2).</p><h4 id="откат-обновления" tabindex="-1">Откат обновления <a class="header-anchor" href="#откат-обновления" aria-label="Permalink to &quot;Откат обновления&quot;">​</a></h4><p>Выполним ещё одно обновление и попробуем развернуть образ, тегированный как <code>v10</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments/kubernetes-bootcamp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kubernetes-bootcamp=gcr.io/google-samples/kubernetes-bootcamp:v10</span></span></code></pre></div><p>Вызовем <code>get deployments</code>, чтобы увидеть статус деплоймента:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments</span></span></code></pre></div><p>Обратите внимание, что вывод показывает недостаток желаемого количества доступных подов. Обратимся к подкоманде <code>get pods</code>, чтобы вывести полный список подов:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>Здесь обратите внимание, что некоторые поды перешли в статус ImagePullBackOff.</p><p>Чтобы получить больше информации о проблеме, выполните подкоманду <code>describe pods</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>В разделе <code>Events</code> вывода по проблемным подам можно увидеть, что новая версия образа (<code>v10</code>) не существует в репозитории.</p><p>Чтобы откатить деплоймент к последней работающей версии, воспользуйтесь подкомандой <code>rollout undo</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rollout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> undo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments/kubernetes-bootcamp</span></span></code></pre></div><p>Команда <code>rollout undo</code> откатывает деплоймент к предыдущему известному состоянию (к образу v2). Обновления версионируются, поэтому можно откатиться к любому предыдущему известному состоянию деплоймента.</p><p>С помощью подкоманды <code>get pods</code> выведем список подов еще раз:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>Четыре пода работают. Проверить, какие версии образа развёрнуты в этих подах, можно подкомандой <code>describe pods</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pods</span></span></code></pre></div><p>Деплоймент снова использует стабильную версию приложения (v2). Откат произошёл успешно.</p><p>Не забудьте очистить содержимое вашего локального кластера:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployments/kubernetes-bootcamp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> services/kubernetes-bootcamp</span></span></code></pre></div><h2 id="альт-сп-kubernetes" tabindex="-1">Альт СП Kubernetes <a class="header-anchor" href="#альт-сп-kubernetes" aria-label="Permalink to &quot;Альт СП Kubernetes&quot;">​</a></h2><h3 id="rootless" tabindex="-1">Rootless <a class="header-anchor" href="#rootless" aria-label="Permalink to &quot;Rootless&quot;">​</a></h3><h4 id="как-посмотреть-логи-сервисов" tabindex="-1">Как посмотреть логи сервисов <a class="header-anchor" href="#как-посмотреть-логи-сервисов" aria-label="Permalink to &quot;Как посмотреть логи сервисов&quot;">​</a></h4><p>Логи kubelet можно посмотреть так:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _SYSTEMD_USER_UNIT=kubelet.service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _UID=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u7s-admin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-b</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span></span></code></pre></div><p>Для CRI-O отдельного user-unit crio.service в данном режиме нет. CRI-O запускается внутри rootlesskit.service, поэтому его логи нужно смотреть через rootlesskit:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _SYSTEMD_USER_UNIT=rootlesskit.service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _UID=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u7s-admin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-b</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span></span></code></pre></div><p>Либо общим поиском по журналу пользователя u7s-admin:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">journalctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _UID=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> u7s-admin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-b</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-pager</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Ei</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;kubelet|crio|cri-o|rootlesskit|nsenter&#39;</span></span></code></pre></div><p>Логи в rootless-режиме нужно искать по записям journal для пользователя u7s-admin.</p><h4 id="nsenter-u7s-rootlessctl-add-ports-0-0-0-0-30443-30443-tcp" tabindex="-1">nsenter_u7s rootlessctl add-ports 0.0.0.0:30443:30443/tcp <a class="header-anchor" href="#nsenter-u7s-rootlessctl-add-ports-0-0-0-0-30443-30443-tcp" aria-label="Permalink to &quot;nsenter_u7s rootlessctl add-ports 0.0.0.0:30443:30443/tcp&quot;">​</a></h4><p>Пробросы, добавленные командой rootlessctl add-ports, являются динамическими и привязаны к текущему экземпляру rootlesskit. При перезапуске rootlesskit они удаляются. Автоматически восстанавливаются только порты, которые добавляются при запуске u7s в скрипте инициализации rootlesskit.</p><p>Для постоянного проброса необходимо добавить требуемый порт в конфигурацию запуска rootlesskit (список автоматически добавляемых портов) либо использовать штатный механизм Kubernetes для публикации сервиса (NodePort/LoadBalancer/hostPort в зависимости от сценария).</p>`,216)]))}const g=i(p,[["render",l]]);export{r as __pageData,g as default};
